import{_ as a,o as i,c as s,ag as o}from"./chunks/framework.ByAj6Cie.js";const m=JSON.parse('{"title":"Análisis de cortocircuito","description":"","frontmatter":{},"headers":[],"relativePath":"es/power-systems/studies/short-circuit-analysis.md","filePath":"es/power-systems/studies/short-circuit-analysis.md"}'),l={name:"es/power-systems/studies/short-circuit-analysis.md"};function r(n,e,c,t,d,p){return i(),s("div",null,[...e[0]||(e[0]=[o('<h1 id="analisis-de-cortocircuito" tabindex="-1">Análisis de cortocircuito <a class="header-anchor" href="#analisis-de-cortocircuito" aria-label="Permalink to &quot;Análisis de cortocircuito&quot;">​</a></h1><h2 id="descripcion-general" tabindex="-1">Descripción general <a class="header-anchor" href="#descripcion-general" aria-label="Permalink to &quot;Descripción general&quot;">​</a></h2><p>El análisis de cortocircuito es el estudio de las corrientes de falla en un sistema de potencia bajo condiciones anormales.</p><p>Determina la magnitud de la corriente que puede fluir durante fallas y cómo responde el sistema.</p><p>Este análisis es esencial para seleccionar equipo, definir configuraciones de protección y asegurar una operación segura.</p><h2 id="proposito" tabindex="-1">Propósito <a class="header-anchor" href="#proposito" aria-label="Permalink to &quot;Propósito&quot;">​</a></h2><p>El propósito del análisis de cortocircuito es:</p><ul><li>Calcular los niveles máximos y mínimos de corriente de falla</li><li>Verificar que el equipo pueda soportar e interrumpir corrientes de falla</li><li>Apoyar la selección adecuada de dispositivos de protección</li><li>Definir configuraciones de protección y coordinación</li><li>Reducir el riesgo de daño al equipo y peligros de seguridad</li></ul><p>Proporciona la base para un diseño de sistema de potencia confiable y seguro.</p><h2 id="como-funciona" tabindex="-1">Cómo funciona <a class="header-anchor" href="#como-funciona" aria-label="Permalink to &quot;Cómo funciona&quot;">​</a></h2><p>El análisis de cortocircuito evalúa el sistema modelando fuentes e impedancias.</p><p>Los elementos clave incluyen:</p><ul><li>Fuentes de energía como suministro del servicio público y generadores</li><li>Transformadores con impedancia definida</li><li>Cables y barras colectoras que contribuyen a la impedancia del sistema</li></ul><p>Cuando ocurre una falla, la impedancia total entre la fuente y la falla determina la corriente de falla.</p><p>Una impedancia menor resulta en mayor corriente de falla.</p><p>Los tipos de falla típicamente analizados incluyen:</p><ul><li>Fallas trifásicas</li><li>Fallas fase a fase</li><li>Fallas fase a tierra</li></ul><p>El análisis calcula la corriente en diferentes puntos del sistema para identificar las condiciones en el peor caso.</p><h2 id="aplicaciones" tabindex="-1">Aplicaciones <a class="header-anchor" href="#aplicaciones" aria-label="Permalink to &quot;Aplicaciones&quot;">​</a></h2><p>El análisis de cortocircuito se utiliza en:</p><ul><li>Diseño de nuevos sistemas de potencia industriales</li><li>Expansión o modificación de instalaciones existentes</li><li>Selección de switchgear (celdas de media tensión), interruptores automáticos y dispositivos de protección</li><li>Verificación de capacidades del equipo</li><li>Estudios de arco eléctrico y evaluaciones de seguridad</li></ul><p>Es un requisito estándar en el diseño de ingeniería y la validación del sistema.</p><h2 id="consideraciones-clave" tabindex="-1">Consideraciones clave <a class="header-anchor" href="#consideraciones-clave" aria-label="Permalink to &quot;Consideraciones clave&quot;">​</a></h2><ul><li><p><strong>Corriente de falla disponible</strong><br> Debe calcularse en cada punto del sistema</p></li><li><p><strong>Capacidades del equipo</strong><br> Deben exceder los niveles de falla calculados</p></li><li><p><strong>Impedancia del sistema</strong><br> Los transformadores y cables influyen significativamente en los resultados</p></li><li><p><strong>Múltiples fuentes</strong><br> Los generadores y suministros en paralelo aumentan los niveles de falla</p></li><li><p><strong>Corriente mínima de falla</strong><br> Importante para asegurar que los dispositivos de protección operen correctamente</p></li><li><p><strong>Expansión futura</strong><br> Cargas o fuentes adicionales pueden cambiar los niveles de falla</p></li></ul><h2 id="notas-practicas" tabindex="-1">Notas prácticas <a class="header-anchor" href="#notas-practicas" aria-label="Permalink to &quot;Notas prácticas&quot;">​</a></h2><ul><li>La corriente de falla es mayor cerca de la fuente de energía y disminuye con la distancia</li><li>La impedancia del transformador es un factor clave para limitar la corriente de falla</li><li>Ignorar la expansión futura puede provocar equipo subdimensionado</li><li>Deben considerarse tanto los escenarios de falla máxima como mínima</li><li>Los datos precisos son críticos para resultados confiables</li></ul>',26)])])}const f=a(l,[["render",r]]);export{m as __pageData,f as default};
